import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CurrencyPair {
  base: string;
  quote: string;
  currentRate: number;
  change: number;
  changePercent: number;
}

interface WeeklyTrend {
  day: string;
  rate: number;
}

interface CurrencyData {
  currencyPair: CurrencyPair;
  weeklyTrend: WeeklyTrend[];
  rateTrend: number[];
}

export default function Widget() {
  const currencyData = response.data as CurrencyData;
  const { currencyPair, weeklyTrend } = currencyData;
  const clipPathId = useId();
  const isPositive = currencyPair.change >= 0;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 360, maxWidth: 480, bgcolor: '#212121' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              {currencyPair.base}/{currencyPair.quote}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFFFFF' }}>
              {currencyPair.currentRate.toFixed(4)}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isPositive ? <ArrowUpward sx={{ fontSize: 16, color: '#4CAF50' }} /> : <ArrowDownward sx={{ fontSize: 16, color: '#F44336' }} />}
              <Typography variant="body2" sx={{ color: isPositive ? '#4CAF50' : '#F44336' }}>
                {currencyPair.change.toFixed(4)} ({currencyPair.changePercent.toFixed(2)}%)
              </Typography>
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: currencyData.rateTrend,
                  color: '#FFC107',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: weeklyTrend.map(w => w.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'rates' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="rates"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
